def rearange_string(s):
    from collections import Counter
    count = Counter(s)
    sorted_chars = sorted(count.items(), key=lambda x: -x[1])
    result = []
    for i in range(len(sorted_chars)):
        if i % 2 == 0:
            result.append(sorted_chars[i][0])
        else:
            result.append(sorted_chars[i-1][0])
    return ''.join(result)

